private:
    TextureData load_blp1_paletted(const std::vector<u8>& file_data, u32 width, u32 height,
                                    u32 mipmap_offset, u32 mipmap_size);
    TextureData load_blp1_jpeg(const std::vector<u8>& file_data, u32 width, u32 height,
