// Helper to write a u32 to a buffer
static void write_u32(std::vector<uint8_t>& buf, uint32_t val) {
    buf.push_back(val & 0xFF);
    buf.push_back((val >> 8) & 0xFF);
    buf.push_back((val >> 16) & 0xFF);
    buf.push_back((val >> 24) & 0xFF);
}

static void write_f32(std::vector<uint8_t>& buf, float val) {
    uint32_t bits;
    std::memcpy(&bits, &val, 4);
    write_u32(buf, bits);
}

static void write_tag(std::vector<uint8_t>& buf, const char* tag) {
    for (int i = 0; i < 4; ++i) buf.push_back(static_cast<uint8_t>(tag[i]));
}

class MdxLoaderTest : public ::testing::Test {
protected:
    // Creates a minimal MDX v800 with one triangle (no bones, no animations)
    void create_minimal_mdx(const std::string& filename) {
        std::vector<uint8_t> data;

        // MDLX magic
        write_tag(data, "MDLX");

        // VERS chunk
        write_tag(data, "VERS");
        write_u32(data, 4);  // chunk size
        write_u32(data, 800); // version

        // GEOS chunk (Geosets) — minimal single triangle
        std::vector<uint8_t> geos;

        // Single geoset
        std::vector<uint8_t> geo;

        // VRTX (vertices) sub-chunk: 3 vertices
        write_tag(geo, "VRTX");
        write_u32(geo, 3);  // count
        // vertex 0: (0, 0, 0)
        write_f32(geo, 0.0f); write_f32(geo, 0.0f); write_f32(geo, 0.0f);
        // vertex 1: (1, 0, 0)
        write_f32(geo, 1.0f); write_f32(geo, 0.0f); write_f32(geo, 0.0f);
        // vertex 2: (0, 1, 0)
        write_f32(geo, 0.0f); write_f32(geo, 1.0f); write_f32(geo, 0.0f);

        // NRMS (normals) sub-chunk
        write_tag(geo, "NRMS");
        write_u32(geo, 3);
        for (int i = 0; i < 3; ++i) {
            write_f32(geo, 0.0f); write_f32(geo, 0.0f); write_f32(geo, 1.0f);
        }

        // PTYP (primitive types) — triangles
        write_tag(geo, "PTYP");
        write_u32(geo, 1);  // 1 group
        write_u32(geo, 4);  // type 4 = triangles

        // PCNT (primitive counts)
        write_tag(geo, "PCNT");
        write_u32(geo, 1);
        write_u32(geo, 3);  // 3 indices in this group

        // PVTX (primitive vertices / indices)
        write_tag(geo, "PVTX");
        write_u32(geo, 3);  // count
        // u16 indices
        geo.push_back(0); geo.push_back(0);
        geo.push_back(1); geo.push_back(0);
        geo.push_back(2); geo.push_back(0);

        // UVBS (UV coordinates)
        write_tag(geo, "UVBS");
        write_u32(geo, 3);
        write_f32(geo, 0.0f); write_f32(geo, 0.0f);
        write_f32(geo, 1.0f); write_f32(geo, 0.0f);
        write_f32(geo, 0.0f); write_f32(geo, 1.0f);

        // Geoset total size = 4 (inclusive size u32) + geo content
        // MDX geoset starts with inclusive size
        write_tag(geos, "");  // placeholder — we write geoset size below

        // Actually, MDX geosets: each geoset starts with u32 inclusive_size
        // Let's restructure:
        std::vector<uint8_t> geos_content;
        uint32_t geo_inclusive_size = static_cast<uint32_t>(4 + geo.size());
        write_u32(geos_content, geo_inclusive_size);
        geos_content.insert(geos_content.end(), geo.begin(), geo.end());

        // GEOS chunk header
        write_tag(data, "GEOS");
        write_u32(data, static_cast<uint32_t>(geos_content.size()));
        data.insert(data.end(), geos_content.begin(), geos_content.end());

        std::ofstream file(filename, std::ios::binary);
        file.write(reinterpret_cast<char*>(data.data()), static_cast<std::streamsize>(data.size()));
    }

    void TearDown() override {
        std::remove("test.mdx");
    }
};

