// engine/assets/src/mdx_loader.cpp
#include <rts/assets/mdx_loader.hpp>
#include <rts/core/logger.hpp>
#include <fstream>
#include <cstring>
#include <stdexcept>

namespace rts {

namespace {

class BinaryReader {
public:
    BinaryReader(const std::vector<u8>& data) : m_data(data) {}

    template <typename T>
    T read() {
        if (m_pos + sizeof(T) > m_data.size()) {
            throw std::runtime_error("MDX: unexpected end of file");
        }
        T val;
        std::memcpy(&val, m_data.data() + m_pos, sizeof(T));
        m_pos += sizeof(T);
        return val;
    }

    std::string read_tag() {
        char tag[5] = {};
        std::memcpy(tag, m_data.data() + m_pos, 4);
        m_pos += 4;
        return std::string(tag, 4);
    }

    void skip(size_t bytes) { m_pos += bytes; }
    size_t pos() const { return m_pos; }
    size_t size() const { return m_data.size(); }
    bool has_data() const { return m_pos < m_data.size(); }
    void seek(size_t pos) { m_pos = pos; }

private:
    const std::vector<u8>& m_data;
    size_t m_pos = 0;
};

ModelData parse_geoset(BinaryReader& reader, size_t end_pos) {
    ModelData model;

    while (reader.pos() < end_pos) {
        std::string sub_tag = reader.read_tag();
        u32 count = reader.read<u32>();

        if (sub_tag == "VRTX") {
            model.vertices.resize(count);
            for (u32 i = 0; i < count; ++i) {
                model.vertices[i].position.x = reader.read<f32>();
                model.vertices[i].position.y = reader.read<f32>();
                model.vertices[i].position.z = reader.read<f32>();
            }
        } else if (sub_tag == "NRMS") {
            for (u32 i = 0; i < count && i < static_cast<u32>(model.vertices.size()); ++i) {
                model.vertices[i].normal.x = reader.read<f32>();
                model.vertices[i].normal.y = reader.read<f32>();
                model.vertices[i].normal.z = reader.read<f32>();
            }
        } else if (sub_tag == "UVBS") {
            for (u32 i = 0; i < count && i < static_cast<u32>(model.vertices.size()); ++i) {
                model.vertices[i].uv.x = reader.read<f32>();
                model.vertices[i].uv.y = reader.read<f32>();
            }
        } else if (sub_tag == "PVTX") {
            model.indices.resize(count);
            for (u32 i = 0; i < count; ++i) {
                model.indices[i] = reader.read<u16>();
            }
        } else if (sub_tag == "PTYP" || sub_tag == "PCNT") {
            // Skip primitive type/count data (u32 per group)
            reader.skip(count * 4);
        } else {
            // Unknown sub-chunk, skip based on count heuristic
            // This is tricky in MDX — for safety, break
            RTS_LOG_WARN("MDX: unknown geoset sub-chunk '{}', stopping geoset parse", sub_tag);
            break;
        }
    }

    return model;
}

void parse_bones(BinaryReader& reader, u32 chunk_size, Skeleton& skeleton) {
    size_t end = reader.pos() + chunk_size;

    while (reader.pos() < end) {
        Bone bone;

        // Bone inherits from Node: read node data
        u32 node_inclusive_size = reader.read<u32>();
        size_t node_end = reader.pos() - 4 + node_inclusive_size;

        // Node name (80 bytes fixed)
        char name[81] = {};
        for (int i = 0; i < 80; ++i) {
            name[i] = static_cast<char>(reader.read<u8>());
        }
        bone.name = std::string(name);

        // objectId, parentId
        reader.read<u32>();  // objectId
        bone.parent_index = reader.read<i32>();

        // Skip rest of node (flags + tracks)
        if (reader.pos() < node_end) {
            reader.seek(node_end);
        }

        // After node: geoset ID and geoset anim ID
        reader.read<u32>();  // geosetId
        reader.read<u32>();  // geosetAnimId

        skeleton.bones.push_back(std::move(bone));
    }
}

void parse_sequences(BinaryReader& reader, u32 chunk_size, Skeleton& skeleton) {
    size_t end = reader.pos() + chunk_size;

    while (reader.pos() < end) {
        AnimationSequence seq;

        // Name (80 bytes fixed)
        char name[81] = {};
        for (int i = 0; i < 80; ++i) {
            name[i] = static_cast<char>(reader.read<u8>());
        }
        seq.name = std::string(name);

        u32 interval_start = reader.read<u32>();
        u32 interval_end = reader.read<u32>();
        seq.duration = static_cast<f32>(interval_end - interval_start);

        // moveSpeed, nonLooping, rarity, syncPoint, bounds
        reader.read<f32>();  // moveSpeed
        u32 non_looping = reader.read<u32>();
        seq.looping = (non_looping == 0);
        reader.read<f32>();  // rarity
        reader.read<u32>();  // syncPoint

        // BoundsRadius + min + max
        reader.read<f32>();  // boundsRadius
        reader.skip(6 * 4);  // min vec3 + max vec3

        skeleton.animations.push_back(std::move(seq));
    }
}

}  // anonymous namespace

std::vector<ModelData> MdxLoader::load(const std::string& path) {
    std::ifstream file(path, std::ios::binary | std::ios::ate);
    if (!file.is_open()) {
        throw std::runtime_error("Failed to open MDX file: " + path);
    }

    auto file_size = file.tellg();
    file.seekg(0);
    std::vector<u8> file_data(static_cast<size_t>(file_size));
    file.read(reinterpret_cast<char*>(file_data.data()), file_size);

    BinaryReader reader(file_data);

    // Verify magic
    std::string magic = reader.read_tag();
    if (magic != "MDLX") {
        throw std::runtime_error("Invalid MDX magic: " + magic);
    }

    std::vector<ModelData> models;
    Skeleton skeleton;

    while (reader.has_data() && reader.pos() + 8 <= reader.size()) {
        std::string tag = reader.read_tag();
        u32 chunk_size = reader.read<u32>();
        size_t chunk_end = reader.pos() + chunk_size;

        if (tag == "VERS") {
            u32 version = reader.read<u32>();
            RTS_LOG_INFO("MDX version: {}", version);
        } else if (tag == "GEOS") {
            // Parse geosets
            while (reader.pos() < chunk_end) {
                u32 geoset_inclusive_size = reader.read<u32>();
                size_t geoset_end = reader.pos() - 4 + geoset_inclusive_size;
                auto model = parse_geoset(reader, geoset_end);
                models.push_back(std::move(model));
                reader.seek(geoset_end);
            }
        } else if (tag == "BONE") {
            parse_bones(reader, chunk_size, skeleton);
        } else if (tag == "SEQS") {
            parse_sequences(reader, chunk_size, skeleton);
        } else {
            // Skip unknown chunks
            reader.skip(chunk_size);
        }
    }

    // Apply skeleton to all models
    if (skeleton.has_bones()) {
        for (auto& model : models) {
            model.skeleton = skeleton;
        }
    }

    RTS_LOG_INFO("MDX loaded: {} geosets, {} bones, {} animations",
                 models.size(), skeleton.bones.size(), skeleton.animations.size());

    return models;
}

}  // namespace rts
