#include <gtest/gtest.h>
#include <rts/terrain/terrain.hpp>
#include <glm/glm.hpp>

TEST(TerrainTest, GeneratesFlatTerrain) {
    std::vector<float> heights(4 * 4, 0.0f);
    auto data = rts::Terrain::generate(heights, 4, 4, 1.0f);

    EXPECT_EQ(data.vertices.size(), 16u);
    // (4-1)*(4-1)*2 triângulos * 3 índices = 54
    EXPECT_EQ(data.indices.size(), 54u);
}

TEST(TerrainTest, HeightQueryReturnsCorrectValue) {
    std::vector<float> heights = {
        0, 0, 0,
        0, 5, 0,
        0, 0, 0
    };
    auto data = rts::Terrain::generate(heights, 3, 3, 1.0f);
    // Vértice central (índice 4) deve ter altura 5
    EXPECT_FLOAT_EQ(data.vertices[4].position.y, 5.0f);
}

TEST(TerrainTest, NormalsAreNormalized) {
    std::vector<float> heights(3 * 3, 0.0f);
    auto data = rts::Terrain::generate(heights, 3, 3, 1.0f);

    for (const auto& v : data.vertices) {
        float len = glm::length(v.normal);
        EXPECT_NEAR(len, 1.0f, 0.01f);
    }
}

TEST(TerrainTest, UVsSpanZeroToOne) {
    std::vector<float> heights(4 * 4, 0.0f);
    auto data = rts::Terrain::generate(heights, 4, 4, 1.0f);

    EXPECT_FLOAT_EQ(data.vertices[0].uv.x, 0.0f);
    EXPECT_FLOAT_EQ(data.vertices[0].uv.y, 0.0f);
    EXPECT_FLOAT_EQ(data.vertices[15].uv.x, 1.0f);
    EXPECT_FLOAT_EQ(data.vertices[15].uv.y, 1.0f);
}

TEST(TerrainTest, HeightAtPosition) {
    std::vector<float> heights = {
        0, 0, 0,
        0,10, 0,
        0, 0, 0
    };
    auto data = rts::Terrain::generate(heights, 3, 3, 1.0f);

    EXPECT_FLOAT_EQ(rts::Terrain::height_at(data, 1.0f, 1.0f), 10.0f);
    EXPECT_FLOAT_EQ(rts::Terrain::height_at(data, 0.0f, 0.0f),  0.0f);
}

