 10→
 11→class BinaryReader {
 12→public:
 13→    explicit BinaryReader(const std::vector<u8>& data) : m_data(data) {}
 14→
 15→    template <typename T>
 16→    T read() {
 17→        if (m_pos + sizeof(T) > m_data.size()) {
 18→            throw std::runtime_error("MDX: unexpected end of file");
 19→        }
 20→        T val;
 21→        std::memcpy(&val, m_data.data() + m_pos, sizeof(T));
 22→        m_pos += sizeof(T);
 23→        return val;
 24→    }
 25→
 26→    std::string read_tag() {
 27→        char tag[5] = {};
 28→        if (m_pos + 4 > m_data.size()) {
 29→            throw std::runtime_error("MDX: unexpected end of file reading tag");
 30→        }
 31→        std::memcpy(tag, m_data.data() + m_pos, 4);
 32→        m_pos += 4;
 33→        return std::string(tag, 4);
 34→    }
 35→
 36→    void   skip(size_t bytes) { m_pos += bytes; }
 37→    size_t pos()              const { return m_pos; }
 38→    size_t size()             const { return m_data.size(); }
 39→    bool   has_data()         const { return m_pos < m_data.size(); }
 40→    void   seek(size_t pos)   { m_pos = pos; }
 41→
 42→private:
 43→    const std::vector<u8>& m_data;
 44→    size_t m_pos = 0;
 45→};
 46→
 47→ModelData parse_geoset(BinaryReader& reader, size_t end_pos) {
 48→    ModelData model;
 49→
 50→    while (reader.pos() < end_pos) {
 51→        if (reader.pos() + 8 > end_pos) break;
 52→
 53→        std::string sub_tag = reader.read_tag();
 54→        u32         count   = reader.read<u32>();
 55→
 56→        if (sub_tag == "VRTX") {
 57→            model.vertices.resize(count);
 58→            for (u32 i = 0; i < count; ++i) {
 59→                model.vertices[i].position.x = reader.read<f32>();
 60→                model.vertices[i].position.y = reader.read<f32>();
 61→                model.vertices[i].position.z = reader.read<f32>();
 62→            }
 63→        } else if (sub_tag == "NRMS") {
 64→            for (u32 i = 0; i < count && i < static_cast<u32>(model.vertices.size()); ++i) {
 65→                model.vertices[i].normal.x = reader.read<f32>();
 66→                model.vertices[i].normal.y = reader.read<f32>();
 67→                model.vertices[i].normal.z = reader.read<f32>();
 68→            }
 69→        } else if (sub_tag == "UVBS") {
 70→            for (u32 i = 0; i < count && i < static_cast<u32>(model.vertices.size()); ++i) {
 71→                model.vertices[i].uv.x = reader.read<f32>();
 72→                model.vertices[i].uv.y = reader.read<f32>();
 73→            }
 74→        } else if (sub_tag == "PVTX") {
 75→            model.indices.resize(count);
 76→            for (u32 i = 0; i < count; ++i) {
 77→                model.indices[i] = reader.read<u16>();
 78→            }
 79→        } else if (sub_tag == "PTYP" || sub_tag == "PCNT") {
 80→            reader.skip(static_cast<size_t>(count) * 4);
 81→        } else {
 82→            // Sub-chunk desconhecido — interrompe parse do geoset
 83→            RTS_LOG_WARN("MDX: unknown geoset sub-chunk '{}', stopping", sub_tag);
 84→            break;
 85→        }
 86→    }
 87→
 88→    return model;
 89→}
 90→
 91→void parse_sequences(BinaryReader& reader, u32 chunk_size, Skeleton& skeleton) {
 92→    const size_t end = reader.pos() + chunk_size;
 93→
 94→    while (reader.pos() + 132 <= end) {
 95→        AnimationSequence seq;
 96→
 97→        char name[81] = {};
 98→        for (int i = 0; i < 80; ++i) name[i] = static_cast<char>(reader.read<u8>());
 99→        seq.name = std::string(name);
100→
101→        reader.read<u32>();  // interval start
102→        u32 interval_end = reader.read<u32>();
103→        seq.duration = static_cast<f32>(interval_end);
104→
105→        reader.read<f32>();  // moveSpeed
106→        u32 non_looping = reader.read<u32>();
107→        seq.looping = (non_looping == 0);
108→        reader.read<f32>();  // rarity
109→        reader.read<u32>();  // syncPoint
110→        reader.read<f32>();  // boundsRadius
111→        reader.skip(6 * 4); // min vec3 + max vec3
112→
113→        skeleton.animations.push_back(std::move(seq));
114→    }
115→}
116→
117→}  // anonymous namespace
118→
119→std::vector<ModelData> MdxLoader::load(const std::string& path) {
120→    std::ifstream file(path, std::ios::binary | std::ios::ate);
121→    if (!file.is_open()) {
122→        throw std::runtime_error("Failed to open MDX file: " + path);
123→    }
124→
125→    auto file_size = file.tellg();
126→    file.seekg(0);
127→    std::vector<u8> file_data(static_cast<size_t>(file_size));
128→    file.read(reinterpret_cast<char*>(file_data.data()), file_size);
129→
130→    BinaryReader reader(file_data);
131→
132→    // Verificar magic
133→    std::string magic = reader.read_tag();
134→    if (magic != "MDLX") {
135→        throw std::runtime_error("Invalid MDX magic: " + magic);
136→    }
137→
138→    std::vector<ModelData> models;
139→    Skeleton               skeleton;
140→
141→    while (reader.has_data() && reader.pos() + 8 <= reader.size()) {
142→        std::string tag        = reader.read_tag();
143→        u32         chunk_size = reader.read<u32>();
144→        size_t      chunk_end  = reader.pos() + chunk_size;
145→
