 32→// ---------------------------------------------------------------------------
 33→// SceneObject
 34→// ---------------------------------------------------------------------------
 35→
 36→struct SceneObject {
 37→    std::string name;
 38→    std::string model_path;
 39→    std::string texture_path;
 40→    std::unique_ptr<rts::Mesh>    mesh;
 41→    std::unique_ptr<rts::Texture> texture;
 42→    rts::Vec3 position = rts::Vec3(0.0f);
 43→    bool visible = true;
 44→};
