#include <imgui.h>
#include "imgui_impl_glfw.h"
#include "imgui_impl_opengl3.h"
#include <GLFW/glfw3.h>
#include <glm/gtc/matrix_transform.hpp>

#include <filesystem>
#include <string>
#include <vector>
#include <memory>
#include <algorithm>

namespace fs = std::filesystem;

// ---------------------------------------------------------------------------
// SceneObject
// ---------------------------------------------------------------------------

struct SceneObject {
    std::string name;
    std::string model_path;
    std::string texture_path;
    std::unique_ptr<rts::Mesh>    mesh;
    std::unique_ptr<rts::Texture> texture;
    rts::Vec3 position = rts::Vec3(0.0f);
    float     scale    = 1.0f;
    bool      visible  = true;
};

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

static std::string file_stem(const std::string& path) {
    return fs::path(path).stem().string();
}

static std::vector<std::string> scan_dir(const std::string& dir,
                                          const std::vector<std::string>& exts) {
    std::vector<std::string> result;
    if (!fs::exists(dir) || !fs::is_directory(dir)) return result;
    for (const auto& entry : fs::directory_iterator(dir)) {
        if (!entry.is_regular_file()) continue;
        std::string ext = entry.path().extension().string();
        std::transform(ext.begin(), ext.end(), ext.begin(), ::tolower);
        for (const auto& e : exts)
            if (ext == e) { result.push_back(entry.path().string()); break; }
    }
    std::sort(result.begin(), result.end());
    return result;
}

static std::string find_matching_texture(const std::string& model_path,
                                          const std::vector<std::string>& textures) {
    std::string ms = file_stem(model_path);
    for (const auto& tex : textures)
        if (file_stem(tex) == ms) return tex;
    return {};
}

static std::unique_ptr<rts::Mesh> load_mesh(rts::AssetManager& assets,
                                              const std::string& path) {
    try {
        auto models = assets.load_model(path);
        if (models.empty() || models[0].vertices.empty()) return nullptr;
        return std::make_unique<rts::Mesh>(models[0].vertices, models[0].indices);
    } catch (const std::exception& e) {
        RTS_LOG_WARN("Falha ao carregar modelo '{}': {}", path, e.what());
        return nullptr;
    }
}

static std::unique_ptr<rts::Texture> load_tex(rts::AssetManager& assets,
                                               const std::string& path) {
    if (path.empty()) return nullptr;
    try {
        auto td = assets.load_texture(path);
        if (td.pixels.empty()) return nullptr;
        return std::make_unique<rts::Texture>(
            td.pixels.data(), td.width, td.height, td.channels);
    } catch (const std::exception& e) {
        RTS_LOG_WARN("Falha ao carregar textura '{}': {}", path, e.what());
        return nullptr;
    }
}

static float default_scale_for_ext(const std::string& path) {
    std::string ext = fs::path(path).extension().string();
    std::transform(ext.begin(), ext.end(), ext.begin(), ::tolower);
    if (ext == ".mdx") return 0.02f;  // WC3 models are ~100-200 units tall
    return 1.0f;
}

static SceneObject make_object(rts::AssetManager& assets,
                                const std::string& model_path,
                                const std::string& texture_path,
                                rts::Vec3 position) {
    SceneObject obj;
    obj.name         = file_stem(model_path);
    obj.model_path   = model_path;
    obj.texture_path = texture_path;
    obj.position     = position;
    obj.scale        = default_scale_for_ext(model_path);
    obj.mesh         = load_mesh(assets, model_path);
    obj.texture      = load_tex(assets, texture_path);
    return obj;
}

// ---------------------------------------------------------------------------
// main
// ---------------------------------------------------------------------------

int main() {
    rts::Logger::init();
    RTS_LOG_INFO("RTS Engine Editor iniciando...");

    rts::WindowConfig win_cfg;
    win_cfg.title  = "RTS Engine Editor";
    win_cfg.width  = 1600;
    win_cfg.height = 900;

    rts::GlfwWindow window(win_cfg);
    rts::Input      input(window.native_handle());
    rts::Time       time;

    rts::Renderer renderer;
    renderer.init();

    rts::RtsCamera camera;
    camera.set_target(rts::Vec3(32.0f, 0.0f, 32.0f));
    camera.set_aspect_ratio(static_cast<float>(window.width()) /
                             static_cast<float>(window.height()));

    // ---- Asset Manager ----
    rts::AssetManager assets;
    assets.register_texture_loader(".png",  std::make_unique<rts::StbLoader>());
    assets.register_texture_loader(".jpg",  std::make_unique<rts::StbLoader>());
    assets.register_texture_loader(".jpeg", std::make_unique<rts::StbLoader>());
    assets.register_texture_loader(".bmp",  std::make_unique<rts::StbLoader>());
    assets.register_texture_loader(".blp",  std::make_unique<rts::BlpLoader>());
    assets.register_model_loader(".gltf",   std::make_unique<rts::GltfLoader>());
    assets.register_model_loader(".glb",    std::make_unique<rts::GltfLoader>());
    assets.register_model_loader(".mdx",    std::make_unique<rts::MdxLoader>());

    // ---- Terreno flat 64x64 ----
    std::vector<float> heights(64 * 64, 0.0f);
    auto terrain_data = rts::Terrain::generate(heights, 64, 64, 1.0f);
    rts::Mesh terrain_mesh(terrain_data.vertices, terrain_data.indices);

    auto terrain_shader = rts::ShaderProgram::from_files(
        "assets/shaders/terrain.vert", "assets/shaders/terrain.frag");
    auto model_shader = rts::ShaderProgram::from_files(
        "assets/shaders/model.vert",   "assets/shaders/model.frag");

    // ---- Scan de assets e carga inicial ----
    const std::vector<std::string> model_exts   = {".mdx", ".gltf", ".glb"};
    const std::vector<std::string> texture_exts = {".blp", ".png", ".jpg", ".jpeg", ".bmp"};

    auto model_paths   = scan_dir("assets/models",   model_exts);
    auto texture_paths = scan_dir("assets/textures", texture_exts);

    std::vector<SceneObject> scene_objects;
    {
        float spacing = 10.0f;
        float n       = static_cast<float>(model_paths.size());
        float start_x = 32.0f - (n - 1.0f) * spacing * 0.5f;
        for (size_t i = 0; i < model_paths.size(); ++i) {
            std::string tex = find_matching_texture(model_paths[i], texture_paths);
            rts::Vec3 pos   = {start_x + static_cast<float>(i) * spacing, 0.0f, 32.0f};
            scene_objects.push_back(make_object(assets, model_paths[i], tex, pos));
        }
    }

    std::vector<std::string> available_textures = texture_paths;

    // ---- ImGui setup ----
    IMGUI_CHECKVERSION();
    ImGui::CreateContext();
    ImGuiIO& io = ImGui::GetIO();
    io.ConfigFlags |= ImGuiConfigFlags_NavEnableKeyboard;
    ImGui::StyleColorsDark();
    ImGui_ImplGlfw_InitForOpenGL(window.native_handle(), true);
    ImGui_ImplOpenGL3_Init("#version 330");

    // Iluminacao
    rts::Vec3 light_dir   = glm::normalize(rts::Vec3(-0.5f, -1.0f, -0.3f));
    rts::Vec3 light_color = rts::Vec3(1.0f, 0.95f, 0.9f);
    rts::Vec3 ambient     = rts::Vec3(0.2f, 0.2f, 0.25f);
    float     tile_scale  = 8.0f;

    // Estado da UI
    int  selected_obj = -1;
    char import_model_buf[512]   = {};
    char import_texture_buf[512] = {};

    RTS_LOG_INFO("Editor pronto — {} modelo(s) carregado(s).", scene_objects.size());

    // ====================================================================
    // Loop principal
    // ====================================================================
    while (!window.should_close()) {
        window.poll_events();
        input.update();
        time.update();

        float dt = time.delta_time();

        rts::Vec2 mouse_pos   = input.mouse_position();
        rts::Vec2 screen_size = {static_cast<float>(window.width()),
                                  static_cast<float>(window.height())};

        if (!io.WantCaptureKeyboard && !io.WantCaptureMouse) {
            camera.update(dt, mouse_pos, screen_size,
                          input.is_key_pressed(GLFW_KEY_W),
                          input.is_key_pressed(GLFW_KEY_A),
                          input.is_key_pressed(GLFW_KEY_S),
                          input.is_key_pressed(GLFW_KEY_D),
                          input.scroll_delta());
        }

        camera.set_aspect_ratio(screen_size.x / std::max(screen_size.y, 1.0f));

        // ---- Render ------------------------------------------------
        renderer.begin_frame();

        // Terreno
        terrain_shader.bind();
        terrain_shader.set_mat4("u_view",        camera.view_matrix());
        terrain_shader.set_mat4("u_projection",  camera.projection_matrix());
        terrain_shader.set_mat4("u_model",       rts::Mat4(1.0f));
        terrain_shader.set_vec3("u_light_dir",   light_dir);
        terrain_shader.set_vec3("u_light_color", light_color);
        terrain_shader.set_vec3("u_ambient",     ambient);
        terrain_shader.set_float("u_tile_scale", tile_scale);

        rts::RenderCommand terrain_cmd;
        terrain_cmd.mesh      = &terrain_mesh;
        terrain_cmd.shader    = &terrain_shader;
        terrain_cmd.transform = rts::Mat4(1.0f);
        renderer.submit(terrain_cmd);

        // Modelos
        model_shader.bind();
        model_shader.set_mat4("u_view",        camera.view_matrix());
        model_shader.set_mat4("u_projection",  camera.projection_matrix());
        model_shader.set_vec3("u_light_dir",   light_dir);
        model_shader.set_vec3("u_light_color", light_color);
        model_shader.set_vec3("u_ambient",     ambient);

        for (auto& obj : scene_objects) {
            if (!obj.visible || !obj.mesh) continue;
            rts::Mat4 transform = glm::translate(rts::Mat4(1.0f), obj.position);
            transform = glm::scale(transform, rts::Vec3(obj.scale));

            rts::RenderCommand cmd;
            cmd.mesh      = obj.mesh.get();
            cmd.texture   = obj.texture.get();
            cmd.shader    = &model_shader;
            cmd.transform = transform;
            renderer.submit(cmd);
        }

        renderer.flush();

        // ---- ImGui -------------------------------------------------
        ImGui_ImplOpenGL3_NewFrame();
        ImGui_ImplGlfw_NewFrame();
        ImGui::NewFrame();

        // -- Barra de info --
        {
            ImGui::SetNextWindowPos(ImVec2(10, 10), ImGuiCond_FirstUseEver);
            ImGui::SetNextWindowSize(ImVec2(260, 0), ImGuiCond_FirstUseEver);
            ImGui::Begin("Info", nullptr, ImGuiWindowFlags_NoResize);
            ImGui::Text("FPS: %.0f", 1.0f / std::max(dt, 0.0001f));
            auto t = camera.target();
            ImGui::Text("Camera: (%.0f, %.0f, %.0f)", t.x, t.y, t.z);
            ImGui::TextDisabled("WASD: Pan | Scroll: Zoom | ESC: Sair");
            ImGui::End();
        }

        // -- Painel Cena (lado esquerdo) --
        {
            ImGui::SetNextWindowPos(ImVec2(10, 100), ImGuiCond_FirstUseEver);
            ImGui::SetNextWindowSize(ImVec2(260, 300), ImGuiCond_FirstUseEver);
            ImGui::Begin("Cena");

            if (ImGui::CollapsingHeader("Objetos", ImGuiTreeNodeFlags_DefaultOpen)) {
                for (int i = 0; i < static_cast<int>(scene_objects.size()); ++i) {
                    auto& obj = scene_objects[i];
                    ImGui::PushID(i);
                    ImGui::Checkbox("##vis", &obj.visible);
                    ImGui::SameLine();
                    bool sel = (selected_obj == i);
                    if (ImGui::Selectable(obj.name.c_str(), sel))
                        selected_obj = (selected_obj == i) ? -1 : i;
                    ImGui::PopID();
                }
            }

            ImGui::Separator();
            if (ImGui::CollapsingHeader("Importar", ImGuiTreeNodeFlags_DefaultOpen)) {
                ImGui::InputText("Modelo",  import_model_buf,   sizeof(import_model_buf));
                ImGui::InputText("Textura", import_texture_buf, sizeof(import_texture_buf));
                if (ImGui::Button("Importar", ImVec2(-1, 0))) {
                    std::string mp = import_model_buf;
                    std::string tp = import_texture_buf;
                    if (!mp.empty()) {
                        float x = 32.0f + static_cast<float>(scene_objects.size()) * 10.0f;
                        scene_objects.push_back(
                            make_object(assets, mp, tp, {x, 0.0f, 32.0f}));
                        if (!tp.empty()) {
                            bool found = false;
                            for (auto& t : available_textures)
                                if (t == tp) { found = true; break; }
                            if (!found) available_textures.push_back(tp);
                        }
                        import_model_buf[0]   = '\0';
                        import_texture_buf[0] = '\0';
                    }
                }
                ImGui::TextDisabled("Ex: assets/models/Footman.mdx");
            }

            ImGui::End();
        }

        // -- Inspector (lado direito) --
        if (selected_obj >= 0 && selected_obj < static_cast<int>(scene_objects.size())) {
            auto& obj = scene_objects[selected_obj];

            float vp_w = io.DisplaySize.x;
            ImGui::SetNextWindowPos(ImVec2(vp_w - 310, 10), ImGuiCond_FirstUseEver);
            ImGui::SetNextWindowSize(ImVec2(300, 0), ImGuiCond_FirstUseEver);
            ImGui::Begin("Inspector");

            ImGui::Text("%s", obj.name.c_str());
            ImGui::TextDisabled("%s", obj.model_path.c_str());
            ImGui::Separator();

            ImGui::Text("Transform");
            ImGui::DragFloat3("Posicao", &obj.position.x, 0.5f);
            ImGui::DragFloat("Escala",   &obj.scale, 0.001f, 0.001f, 10.0f, "%.3f");
            ImGui::Separator();

            ImGui::Text("Textura");
            std::string preview_str = obj.texture_path.empty()
                                          ? "(nenhuma)"
                                          : file_stem(obj.texture_path);
            if (ImGui::BeginCombo("##tex", preview_str.c_str())) {
                if (ImGui::Selectable("(nenhuma)", obj.texture_path.empty())) {
                    obj.texture_path.clear();
                    obj.texture.reset();
                }
                for (const auto& tp : available_textures) {
                    bool is_sel = (tp == obj.texture_path);
                    if (ImGui::Selectable(file_stem(tp).c_str(), is_sel)) {
                        if (tp != obj.texture_path) {
                            obj.texture_path = tp;
                            obj.texture      = load_tex(assets, tp);
                        }
                    }
                }
                ImGui::EndCombo();
            }

            if (!obj.mesh)
                ImGui::TextColored(ImVec4(1, 0.4f, 0.4f, 1), "Mesh nao carregada");
            if (!obj.texture && !obj.texture_path.empty())
                ImGui::TextColored(ImVec4(1, 0.7f, 0.3f, 1), "Textura nao carregada");

            ImGui::End();
        }

        ImGui::Render();
        ImGui_ImplOpenGL3_RenderDrawData(ImGui::GetDrawData());

        window.swap_buffers();

        if (input.is_key_pressed(GLFW_KEY_ESCAPE)) break;
    }

    ImGui_ImplOpenGL3_Shutdown();
    ImGui_ImplGlfw_Shutdown();
    ImGui::DestroyContext();

    RTS_LOG_INFO("Editor encerrado.");
    return 0;
}

