 31→// ---------------------------------------------------------------------------
 32→// SceneObject
 33→// ---------------------------------------------------------------------------
 34→
 35→struct SceneObject {
 36→    std::string name;
 37→    std::string model_path;
 38→    std::string texture_path;
 39→    std::unique_ptr<rts::Mesh>    mesh;
 40→    std::unique_ptr<rts::Texture> texture;
 41→    rts::Vec3 position = rts::Vec3(0.0f);
 42→    float     scale    = 1.0f;
 43→    bool      visible  = true;
 44→};
 45→
 46→// ---------------------------------------------------------------------------
 47→// Helpers
 48→// ---------------------------------------------------------------------------
 49→
 50→static std::string file_stem(const std::string& path) {
 51→    return fs::path(path).stem().string();
 52→}
 53→
 54→static std::vector<std::string> scan_dir(const std::string& dir,
 55→                                          const std::vector<std::string>& exts) {
 56→    std::vector<std::string> result;
 57→    if (!fs::exists(dir) || !fs::is_directory(dir)) return result;
 58→    for (const auto& entry : fs::directory_iterator(dir)) {
 59→        if (!entry.is_regular_file()) continue;
 60→        std::string ext = entry.path().extension().string();
 61→        std::transform(ext.begin(), ext.end(), ext.begin(), ::tolower);
 62→        for (const auto& e : exts)
 63→            if (ext == e) { result.push_back(entry.path().string()); break; }
 64→    }
 65→    std::sort(result.begin(), result.end());
 66→    return result;
 67→}
 68→
 69→static std::string find_matching_texture(const std::string& model_path,
 70→                                          const std::vector<std::string>& textures) {
 71→    std::string ms = file_stem(model_path);
 72→    for (const auto& tex : textures)
 73→        if (file_stem(tex) == ms) return tex;
 74→    return {};
 75→}
 76→
 77→static std::unique_ptr<rts::Mesh> load_mesh(rts::AssetManager& assets,
 78→                                              const std::string& path) {
 79→    try {
 80→        auto models = assets.load_model(path);
 81→        if (models.empty() || models[0].vertices.empty()) return nullptr;
 82→        return std::make_unique<rts::Mesh>(models[0].vertices, models[0].indices);
 83→    } catch (const std::exception& e) {
 84→        RTS_LOG_WARN("Falha ao carregar modelo '{}': {}", path, e.what());
 85→        return nullptr;
 86→    }
 87→}
 88→
 89→static std::unique_ptr<rts::Texture> load_tex(rts::AssetManager& assets,
 90→                                               const std::string& path) {
 91→    if (path.empty()) return nullptr;
 92→    try {
 93→        auto td = assets.load_texture(path);
 94→        if (td.pixels.empty()) return nullptr;
 95→        return std::make_unique<rts::Texture>(
 96→            td.pixels.data(), td.width, td.height, td.channels);
 97→    } catch (const std::exception& e) {
 98→        RTS_LOG_WARN("Falha ao carregar textura '{}': {}", path, e.what());
 99→        return nullptr;
100→    }
101→}
102→
103→static float default_scale_for_ext(const std::string& path) {
104→    std::string ext = fs::path(path).extension().string();
105→    std::transform(ext.begin(), ext.end(), ext.begin(), ::tolower);
106→    if (ext == ".mdx") return 0.02f;  // WC3 models are ~100-200 units tall
107→    return 1.0f;
108→}
109→
110→static SceneObject make_object(rts::AssetManager& assets,
111→                                const std::string& model_path,
112→                                const std::string& texture_path,
113→                                rts::Vec3 position) {
114→    SceneObject obj;
115→    obj.name         = file_stem(model_path);
116→    obj.model_path   = model_path;
117→    obj.texture_path = texture_path;
118→    obj.position     = position;
119→    obj.scale        = default_scale_for_ext(model_path);
120→    obj.mesh         = load_mesh(assets, model_path);
121→    obj.texture      = load_tex(assets, texture_path);
122→    return obj;
123→}
