 36→static std::string file_stem(const std::string& path) {
 37→    return fs::path(path).stem().string();
 38→}
 39→
 40→static std::vector<std::string> scan_dir(const std::string& dir,
 41→                                          const std::vector<std::string>& exts) {
 42→    std::vector<std::string> result;
 43→    if (!fs::exists(dir) || !fs::is_directory(dir)) return result;
 44→    for (const auto& entry : fs::directory_iterator(dir)) {
 45→        if (!entry.is_regular_file()) continue;
 46→        std::string ext = entry.path().extension().string();
 47→        std::transform(ext.begin(), ext.end(), ext.begin(), ::tolower);
 48→        for (const auto& e : exts)
 49→            if (ext == e) { result.push_back(entry.path().string()); break; }
 50→    }
 51→    std::sort(result.begin(), result.end());
 52→    return result;
 53→}
