 55→static std::string find_matching_texture(const std::string& model_path,
 56→                                          const std::vector<std::string>& textures) {
 57→    std::string ms = file_stem(model_path);
 58→    for (const auto& tex : textures)
 59→        if (file_stem(tex) == ms) return tex;
 60→    return {};
 61→}
