 63→static std::unique_ptr<rts::Mesh> load_mesh(rts::AssetManager& assets,
 64→                                              const std::string& path) {
 65→    try {
 66→        auto models = assets.load_model(path);
 67→        if (models.empty() || models[0].vertices.empty()) return nullptr;
 68→        return std::make_unique<rts::Mesh>(models[0].vertices, models[0].indices);
 69→    } catch (const std::exception& e) {
