 89→// Gera heightmap procedural com colinas suaves
 90→static std::vector<float> generate_hills(rts::u32 w, rts::u32 h, float max_height) {
 91→    std::vector<float> heights(w * h);
 92→    for (rts::u32 z = 0; z < h; ++z) {
 93→        for (rts::u32 x = 0; x < w; ++x) {
 94→            float fx = static_cast<float>(x) / static_cast<float>(w);
 95→            float fz = static_cast<float>(z) / static_cast<float>(h);
 96→
 97→            float h1 = std::sin(fx * 3.14159f * 2.0f) * std::cos(fz * 3.14159f * 2.0f);
 98→            float h2 = std::sin(fx * 3.14159f * 4.0f + 1.0f) * 0.5f;
 99→            float h3 = std::cos(fz * 3.14159f * 3.0f + 2.0f) * 0.3f;
100→
101→            // Borda mais baixa para evitar cortes visuais
102→            float edge_x = std::min(fx, 1.0f - fx) * 4.0f;
103→            float edge_z = std::min(fz, 1.0f - fz) * 4.0f;
104→            float edge   = std::min(std::min(edge_x, edge_z), 1.0f);
105→
106→            heights[z * w + x] = (h1 + h2 + h3) * max_height * edge * 0.3f
107→                                  + max_height * 0.1f;
108→        }
109→    }
110→    return heights;
111→}
