static std::string find_matching_texture(const std::string& model_path,
                                          const std::vector<std::string>& textures) {
    std::string ms = file_stem(model_path);
    // Preferir formatos standard (bmp/png/jpg) sobre blp
    std::string blp_match;
    for (const auto& tex : textures) {
        if (file_stem(tex) != ms) continue;
        std::string ext = fs::path(tex).extension().string();
        std::transform(ext.begin(), ext.end(), ext.begin(), ::tolower);
        if (ext != ".blp") return tex;  // formato standard — retorna direto
        if (blp_match.empty()) blp_match = tex;
    }
    return blp_match;  // fallback pra blp, ou vazio
}

